+import { DynamoDBToolboxError } from '~/errors/index.js'
+import type { MapSchema, ItemSchema, Schema, SchemaProps, WriteMode } from '~/schema/index.js'
+import { formatArrayPath } from '~/schema/actions/utils/formatArrayPath.js'
+
+export const addRequiredIf = (
+  props: SchemaProps,
+  attributeName: string,
+  triggerValues: unknown[]
+): void => {
+  props.requiredIf ??= {}
+  props.requiredIf[attributeName] = [...(props.requiredIf[attributeName] ?? []), ...triggerValues]
+}
+
+export const checkConditionalRequirements = (
+  schema: MapSchema | ItemSchema,
+  value: Record<string, unknown>,
+  mode: WriteMode,
+  valuePath: (string | number)[] = []
+): void => {
+  if (mode !== 'put') return
+
+  for (const [attributeName, attribute] of Object.entries(schema.attributes)) {
+    if (attribute.props.required === 'always' || value[attributeName] !== undefined) continue
+    for (const [controllerName, triggerValues] of Object.entries(attribute.props.requiredIf ?? {})) {
+      if (value[controllerName] !== undefined && triggerValues.some(value => value === value[controllerName])) {
+        const path = formatArrayPath([...valuePath, attributeName])
+        throw new DynamoDBToolboxError('parsing.attributeRequired', {
+          message: `Attribute '${path}' is required.`, path
+        })
+      }
+    }
+  }
+}
+
+export const checkRequiredIfReferences = (schema: MapSchema | ItemSchema, path?: string): void => {
+  for (const [attributeName, attribute] of Object.entries(schema.attributes)) {
+    for (const controllerName of Object.keys(attribute.props.requiredIf ?? {})) {
+      if (!(controllerName in schema.attributes)) {
+        throw new DynamoDBToolboxError('schema.requiredIf.invalidAttribute', {
+          message: `Invalid requiredIf${path !== undefined ? ` at path '${path}'` : ''}: '${controllerName}' is not a sibling attribute.`, path,
+          payload: { attributeName, controllerName }
+        })
+      }
+      if (controllerName === attributeName) {
+        throw new DynamoDBToolboxError('schema.requiredIf.selfReference', {
+          message: `Invalid requiredIf${path !== undefined ? ` at path '${path}'` : ''}: an attribute cannot reference itself.`, path,
+          payload: { attributeName }
+        })
+      }
+      if (schema.attributes[attributeName]?.props.key || schema.attributes[controllerName]?.props.key) {
+        throw new DynamoDBToolboxError('schema.requiredIf.keyAttribute', {
+          message: `Invalid requiredIf${path !== undefined ? ` at path '${path}'` : ''}: key attributes cannot participate.`, path,
+          payload: { attributeName, controllerName }
+        })
+      }
+    }
+  }
+}
